                    val ackRes = billingClient.acknowledgePurchase(
                        AcknowledgePurchaseParams.newBuilder().setPurchaseToken(purchase.purchaseToken).build()
                    )
                    if (ackRes.responseCode != BillingClient.BillingResponseCode.OK) {
                        dispatchResult(PaymentResult.Failure("ACK_${ackRes.responseCode}", ackRes.debugMessage, recoverable = true))
                        return
                    }
                }

                markPurchaseTokenProcessed(purchaseTokenHash)

                val txId = newTransactionId()
                dispatchResult(PaymentResult.Success(txId, mapOf("purchaseTokenHash" to purchaseTokenHash)))

                val shouldConsume = purchase.products.any { productId ->
                    val pd = productDetailsCache[productId]
                    pd?.productType == BillingClient.ProductType.INAPP
                }

                if (shouldConsume) {
                    val consumeRes = billingClient.consumePurchase(
                        ConsumeParams.newBuilder().setPurchaseToken(purchase.purchaseToken).build()
                    )
                    if (consumeRes.billingResult.responseCode != BillingClient.BillingResponseCode.OK) {
                        config.logger.warn("consume_failed", mapOf("code" to consumeRes.billingResult.responseCode.toString(), "msg" to consumeRes.billingResult.debugMessage))
                    }
                }
            }

            Purchase.PurchaseState.PENDING -> {
                val txId = newTransactionId()
                dispatchResult(PaymentResult.Pending(txId, mapOf("purchaseTokenHash" to purchaseTokenHash)))
            }

            else -> {
                dispatchResult(PaymentResult.Failure("PURCHASE_STATE_${purchase.purchaseState}", "Unsupported purchase state", recoverable = false))
            }
        }
    }

    private fun dispatchResult(result: PaymentResult) {
