    private suspend fun emitWalletUpdate() {
        withContext(Dispatchers.Main) {
            val balance = getWalletBalanceMinor()
            val currency = getWalletCurrency()
            listeners.values.forEach {
                try {
                    it.onWalletUpdated(balance, currency)
                } catch (_: Throwable) {}
            }
        }
    }

    private fun applyWalletTransaction(tx: WalletTransaction): PaymentResult {
        val currency = getWalletCurrency()
        if (!tx.currency.equals(currency, ignoreCase = true)) {
            return PaymentResult.Failure("CURRENCY_MISMATCH", "Wallet currency mismatch", recoverable = false)
        }

        val current = getWalletBalanceMinor()
        val newBalance = when (tx.type) {
            WalletTransaction.Type.CREDIT -> safeAdd(current, tx.amountMinor) ?: return PaymentResult.Failure("OVERFLOW", "Balance overflow", recoverable = false)
            WalletTransaction.Type.DEBIT -> current - tx.amountMinor
        }

        prefs.edit()
            .putLong(Keys.WALLET_BALANCE_MINOR, newBalance)
            .putString(Keys.WALLET_CURRENCY, currency)
            .apply()

        appendWalletTx(tx)

        scope.launch { emitWalletUpdate() }

        return PaymentResult.Success(tx.id, mapOf("wallet" to "true"))
    }

    private fun appendWalletTx(tx: WalletTransaction) {
        val encoded = encodeWalletTx(tx)
        val existing = prefs.getString(Keys.WALLET_TX_LOG, null)
        val updated = if (existing.isNullOrBlank()) encoded else existing + "\n" + encoded
        val trimmed = trimWalletLog(updated, maxLines = 500)
        prefs.edit().putString(Keys.WALLET_TX_LOG, trimmed).apply()
    }

    private fun trimWalletLog(log: String, maxLines: Int): String {
        val lines = log.split('\n').filter { it.isNotBlank() }
        if (lines.size <= maxLines) return lines.joinToString("\n")
        return lines.takeLast(maxLines).joinToString("\n")
    }

    private fun encodeWalletTx(tx: WalletTransaction): String {
        val meta = tx.metadata.entries.joinToString("&") { "${escape(it.key)}=${escape(it.value)}" }
        val ref = tx.reference?.let { escape(it) } ?: ""
        return listOf(
            escape(tx.id),
            tx.type.name,
            tx.amountMinor.toString(),
            escape(tx.currency),
            tx.createdAtEpochMs.toString(),
            ref,
            meta
        ).joinToString("|")
    }

    private fun decodeWalletTx(line: String): WalletTransaction? {
        val parts = line.split('|')
        if (parts.size < 7) return null
        val id = unescape(parts[0])
        val type = runCatching { WalletTransaction.Type.valueOf(parts[1]) }.getOrNull() ?: return null
        val amount = parts[2].toLongOrNull() ?: return null
        val currency = unescape(parts[3])
        val created = parts[4].toLongOrNull() ?: return null
        val ref = unescape(parts[5]).ifBlank { null }
        val metaRaw = parts[6]
        val meta = if (metaRaw.isBlank()) emptyMap() else metaRaw.split('&').mapNotNull {
            val idx = it.indexOf('=')
            if (idx <= 0) null else unescape(it.substring(0, idx)) to unescape(it.substring(idx + 1))
        }.toMap()
        return WalletTransaction(id, type, amount, currency, created, ref, meta)
    }

    private fun sanitizeMetadata(metadata: Map<String, String>): Map<String, String> {
        if (metadata.isEmpty()) return emptyMap()
        val out = LinkedHashMap<String, String>(metadata.size)
        for ((k, v) in metadata) {
            val key = k.take(64)
            val value = v.take(256)
            out[key] = value
        }
        return out
    }

    private fun escape(s: String): String {
        return s.replace("%", "%25").replace("|", "%7C").replace("\n", "%0A").replace("&", "%26").replace("=", "%3D")
    }

    private fun unescape(s: String): String {
        return s.replace("%3D", "=").replace("%26", "&").replace("%0A", "\n").replace("%7C", "|").replace("%25", "%")
    }

    private fun newTransactionId(): String {
        val base = UUID.randomUUID().toString()
        val userHash = sha256(config.appUserId).take(12)
        return "tx_${userHash}_${base.replace("-", "")}"
    }

    private fun isPurchaseTokenProcessed(tokenHash: String): Boolean {
        val set = prefs.getStringSet(Keys.PROCESSED_PURCHASE_TOKENS, emptySet()) ?: emptySet()
        return set.contains(tokenHash)
    }

    private fun markPurchaseTokenProcessed(tokenHash: String) {
        val set = (prefs.getStringSet(Keys.PROCESSED_PURCHASE_TOKENS, emptySet()) ?: emptySet()).toMutableSet()
        if (set.add(tokenHash)) {
            prefs.edit().putStringSet(Keys.PROCESSED_PURCHASE_TOKENS, set).apply()
        }
    }

    private fun sha256(input: String): String {
        val md = MessageDigest.getInstance("SHA-256")
        val bytes = md.digest(input.toByteArray(Charsets.UTF_8))
        val sb = StringBuilder(bytes.size * 2)
        for (b in bytes) sb.append(((b.toInt() and 0xff) + 0x100).toString(16).substring(1))
        return sb.toString()
    }

    private fun safeAdd(a: Long, b: Long): Long? {
        val res = a + b
        if (((a xor res) and (b xor res)) < 0) return null
        return res
    }

    private object Keys {
        const val PREFS_NAME = "payment_secure_store"
        const val WALLET_BALANCE_MINOR = "wallet_balance_minor"
        const val WALLET_CURRENCY = "wallet_currency"
        const val WALLET_TX_LOG = "wallet_tx_log"
        const val PROCESSED_PURCHASE_TOKENS = "processed_purchase_tokens"
    }
}

private fun createSecurePrefs(
    context: Context,
    allowFallback: Boolean,
    logger: PaymentLogger
): SharedPreferences {
    val appContext = context.applicationContext
    return try {
        val masterKey = MasterKey.Builder(appContext)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .build()

        EncryptedSharedPreferences.create(
            appContext,
            PaymentModule::class.java.name + "_" + "v1",
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    } catch (t: Throwable) {
        logger.error(
            "secure_prefs_init_failed",
            mapOf(
                "sdk" to Build.VERSION.SDK_INT.toString(),
                "manufacturer" to Build.MANUFACTURER.orEmpty(),
                "model" to Build.MODEL.orEmpty()
            ),
            t
        )
        if (!allowFallback) throw t
        appContext.getSharedPreferences(PaymentModule::class.java.name + "_insecure_fallback_v1", Context.MODE_PRIVATE)
    }
}

suspend fun BillingClient.consumePurchase(params: ConsumeParams): com.android.billingclient.api.ConsumeResult {
    return kotlinx.coroutines.suspendCancellableCoroutine { cont ->
        consumeAsync(params) { billingResult, purchaseToken ->
            if (cont.isActive) cont.resume(com.android.billingclient.api.ConsumeResult(billingResult, purchaseToken), onCancellation = null)
        }
    }
}

data class ConsumeResultCompat(val billingResult: BillingResult, val purchaseToken: String)

@Suppress("FunctionName")
private fun com.android.billingclient.api.ConsumeResult(billingResult: BillingResult, purchaseToken: String): com.android.billingclient.api.ConsumeResult {
    return object : com.android.billingclient.api.ConsumeResult {
        override fun getBillingResult(): BillingResult = billingResult
        override fun getPurchaseToken(): String = purchaseToken
    }
}